     return std::move(*this).ValueOrImpl(std::forward<U>(default_value));
   }

+  // StatusOr<T>::or_else()
+  //
+  // Invokes the given callable with the held `absl::Status` when this
+  // `StatusOr` holds an error, returning a new `StatusOr<T>` produced by
+  // the callable. If this `StatusOr` holds a value, it is returned unchanged.
+  template <typename Fn>
+  StatusOr<T> or_else(Fn&& fn) const& {
+    if (ok()) return *this;
+    return std::forward<Fn>(fn)(status());
+  }
+
+  template <typename Fn>
+  StatusOr<T> or_else(Fn&& fn) && {
+    if (ok()) return std::move(*this);
+    return std::forward<Fn>(fn)(std::move(*this).status());
+  }
